        </div>
      </div>
    </div>
  );
};

// ─── STUDENT PROFILE ──────────────────────────────────────────────────────────
export const StudentProfile = () => {
  const [form, setForm]       = useState({ name: "", email: "", phone: "", address: "", department: "", gender: "" });
  const [depts, setDepts]     = useState([]);
  const [saving, setSaving]   = useState(false);
  const [loading, setLoading] = useState(true);
  const fileRef               = useRef(null);

  const { pct, missing } = calcProfileCompletion("student", form);

  useEffect(() => {
    Promise.all([getStudentProfile(), fetchDepartments()])
      .then(([p, d]) => {
        setForm({
          name:       p?.name       || "",
          email:      p?.email      || "",
          phone:      p?.phone      || "",
          address:    p?.address    || "",
          department: p?.department || "",
          gender:     p?.gender     || "",
          userId:     p?.userId     || "",
          profilePicUrl: p?.profilePicUrl || "",
        });
        setDepts(Array.isArray(d) ? d : []);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    try {
      setSaving(true);
      await updateStudentProfile({
        name:       form.name,
        phone:      form.phone,
        address:    form.address,
        department: form.department,
        gender:     form.gender,
      });
      alert("Profile updated successfully!");
    } catch (err) {
      alert("Failed: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  // ── Profile photo upload ───────────────────────────────────────────────────
  const handleFileChange = async (e) => {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      const dataUrl = ev.target.result;
      setForm(f => ({ ...f, profilePicUrl: dataUrl }));
      try {
        setUploading(true);
        await updateStudentProfile({ profilePicUrl: dataUrl });
      } catch (err) { alert("Photo upload failed: " + err.message); setForm(f => ({ ...f, profilePicUrl: "" })); }
      finally { setUploading(false); }
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const handleRemovePhoto = async () => {
    setForm(f => ({ ...f, profilePicUrl: "" }));
    await updateStudentProfile({ profilePicUrl: "" }).catch(console.error);
  };

  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;

  return (
     <div className="fade-up">
      <PageHeader title="My Profile" />
      <ProfileAlert pct={pct} missing={missing} onComplete={() => fileRef.current?.click()} />

      {/* Hidden file input */}
      <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFileChange} />

      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 24 }}>
        {/* Left card — avatar + photo upload */}
        <Card style={{ textAlign: "center", padding: 32 }}>
          <DonutChart pct={pct} color={T.primaryL} label="Complete" />
          <div style={{ fontSize: 13, fontWeight: 700, color: T.accentY, marginTop: 8 }}>Profile {pct}% Complete</div>

          {/* Profile photo or avatar */}
          <div style={{ position: "relative", width: 80, margin: "16px auto 0" }}>
            {form.profilePicUrl ? (
              <div style={{ width: 80, height: 80, borderRadius: "50%", overflow: "hidden", border: `3px solid ${T.primaryL}` }}>
                <img src={form.profilePicUrl} alt="Profile" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              </div>
            ) : (
              <Avatar name={form.name || "S"} size={80} color={T.accent} />
            )}
            {uploading && (
              <div style={{ position: "absolute", inset: 0, borderRadius: "50%", background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>⏳</div>
            )}
          </div>

          <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, marginTop: 12 }}>{form.name || "—"}</div>
          <div style={{ fontSize: 13, color: T.muted }}>{form.userId || "—"}</div>
          {form.department && <Badge type="info" style={{ marginTop: 6 }}>{form.department}</Badge>}

          {/* Photo buttons */}
          <Btn variant="dark" size="sm" full style={{ marginTop: 16 }} disabled={uploading}
            onClick={() => fileRef.current?.click()}>
            📷 {uploading ? "Uploading…" : form.profilePicUrl ? "Change Photo" : "Upload Photo (Optional)"}
          </Btn>
          {form.profilePicUrl && !uploading && (
            <Btn variant="ghost" size="sm" full style={{ marginTop: 8 }} onClick={handleRemovePhoto}>
              ✕ Remove Photo
            </Btn>
          )}
        </Card>

        {/* Right card — form fields */}
        <Card style={{ padding: 28 }}>
          <div style={{ fontFamily: "Syne", fontSize: 17, fontWeight: 800, marginBottom: 20 }}>Update Profile</div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Full Name *"    value={form.name}  onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="Your full name" />
            <Input label="Email Address"  value={form.email} onChange={() => {}} style={{ opacity: 0.6, cursor: "not-allowed" }} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Phone Number *" value={form.phone}  onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} placeholder="+91 98765 43210" />
            <Select label="Gender" value={form.gender} onChange={e => setForm(f => ({ ...f, gender: e.target.value }))}
              options={[{ value: "", label: "Select Gender" }, "Male", "Female", "Other"].map(o => typeof o === "string" ? { value: o, label: o } : o)} />
          </div>

          {/* Department dropdown — loaded from backend */}
          <Select
            label="Department *"
            value={form.department}
            onChange={e => setForm(f => ({ ...f, department: e.target.value }))}
            options={[
              { value: "", label: depts.length === 0 ? "No departments available — contact admin" : "-- Select Department --" },
              ...depts.map(d => ({ value: d.name, label: d.name })),
            ]}
          />

          {depts.length === 0 && (
            <div style={{ fontSize: 12, color: T.accentY, marginTop: -10, marginBottom: 14 }}>
              ⚠️ No departments found. Ask your admin to create departments first.
            </div>
          )}

          <Input label="Address" value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} placeholder="Street address, City, Pincode" />

          <Btn variant="primary" size="lg" onClick={handleSave} disabled={saving || uploading}>
            {saving ? "Saving…" : "Save Profile →"}
          </Btn>
        </Card>
      </div>
    </div>
  );
};

