      .finally(() => setLoading(false));
  }, []);

  const handleMarkRead = async (id) => {
    try {
      await markStudentNotifRead(id);
      setNotifs(n => n.map(x => x.id === id ? { ...x, read: true } : x));
    } catch (err) { console.error(err); }
  };

  const handleMarkAll = async () => {
    const unread = notifs.filter(n => !n.read);
    await Promise.all(unread.map(n => markStudentNotifRead(n.id))).catch(console.error);
    setNotifs(n => n.map(x => ({ ...x, read: true })));
  };

  const typeIcon = { INFO: "ℹ️", WARNING: "⚠️", SUCCESS: "✅", ERROR: "❌" };

  return (
    <div className="fade-up">
      <PageHeader title="Notifications"
        actions={[<Btn variant="ghost" size="sm" onClick={handleMarkAll}>Mark All Read</Btn>]} />
      <Card>
        {loading ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        ) : notifs.length === 0 ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>No notifications yet.</div>
        ) : (
          notifs.map(n => (
            <div key={n.id}
              style={{ display: "flex", gap: 14, padding: "12px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "flex-start", cursor: !n.read ? "pointer" : "default" }}
              onClick={() => !n.read && handleMarkRead(n.id)}
            >
              <div style={{ width: 38, height: 38, background: `${T.primary}18`, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                {typeIcon[n.type] || "🔔"}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 14, fontWeight: n.read ? 500 : 700 }}>{n.title}</div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>{n.message}</div>
                <div style={{ fontSize: 10, color: T.muted, marginTop: 4 }}>
                  {n.createdAt ? new Date(n.createdAt).toLocaleString("en-IN") : ""}
                </div>
              </div>
              {!n.read && <div style={{ width: 8, height: 8, borderRadius: "50%", background: T.primaryL, flexShrink: 0, marginTop: 5 }} />}
            </div>
          ))
        )}
      </Card>
    </div>
  );
};

// ─── STUDENT ANNOUNCEMENTS ────────────────────────────────────────────────────
export const StudentAnnouncements = () => {
  const [items, setItems]     = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getStudentAnnouncements()
      .then(d => setItems(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="fade-up">
      <PageHeader title="Announcements" subtitle="Messages from admin and your teachers" />
      <Card>
        {loading ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        ) : items.length === 0 ? (
          <div style={{ padding: 32, textAlign: "center", color: T.muted }}>No announcements yet.</div>
        ) : (
          items.map(a => (
            <div key={a.id} style={{ padding: "14px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, display: "flex", gap: 14 }}>
              <div style={{ width: 40, height: 40, background: `${T.primary}18`, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>📢</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{a.title}</div>
                <div style={{ fontSize: 13, color: T.muted, margin: "4px 0" }}>{a.content}</div>
                <div style={{ fontSize: 11, color: T.muted }}>
                  By {a.authorName} · {a.createdAt ? new Date(a.createdAt).toLocaleDateString("en-IN") : ""}
                </div>
              </div>
            </div>
          ))
        )}
      </Card>
    </div>
  );
};

// ─── STUDENT DASHBOARD WRAPPER ────────────────────────────────────────────────
const STUDENT_PAGES = {
  overview:      StudentOverview,
  profile:       StudentProfile,
  courses:       StudentCourses,
  tasks:         StudentTasks,
  fees:          StudentFees,
  notifications: StudentNotifications,
  announcements: StudentAnnouncements,
};

const StudentDashboard = ({ onLogout }) => {
  const [page, setPage]       = useState("overview");
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    getStudentProfile().then(setProfile).catch(console.error);
  }, []);

  const { pct, missing } = calcProfileCompletion("student", profile || {});
  const Comp = STUDENT_PAGES[page] || STUDENT_PAGES.overview;

  return (
    <DashLayout role="student" page={page} onNav={setPage} onLogout={onLogout}>
      <ProfileAlert pct={pct} missing={missing} onComplete={() => setPage("profile")} />
      <Comp onNav={setPage} />
    </DashLayout>
  );
};

export default StudentDashboard;
